fn main() {
    let numbers = vec![1, 2, 3];
    for i in &numbers {
        match *i {
            0 | 1 | 2 => println!("Small number: {}", i),
            _ => panic!("Out of bounds!"),
        }
    }
}

fixed_code:
fn main() {
    let numbers = vec![1, 2, 3];
    for i in &numbers {
        match *i {
            0 | 1 | 2 => println!("Small number: {}", i),
            _ if *i <= numbers.len() => println!("Valid index: {}", i),
            _ => panic!("Out of bounds!"),
        }
    }
}

